namespace sv_2e01b680450645b7a5f345f6d45a4960.Client;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_2e01b680450645b7a5f345f6d45a4960.Client;

/// <summary>
/// Reads the authenticated user's claims from <see cref="PersistentComponentState"/>
/// so that identity survives the Server → WebAssembly handoff.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask = _unauthenticated;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
            return;

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "Persisted"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_2e01b680450645b7a5f345f6d45a4960.Auth;

/// <summary>
/// A server-side <see cref="AuthenticationStateProvider"/> that always returns
/// a hardcoded authenticated user for demonstration purposes.
/// </summary>
public sealed class FakeAuthenticationStateProvider : AuthenticationStateProvider
{
    private readonly Task<AuthenticationState> _authenticationState;

    public FakeAuthenticationStateProvider()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "FakeAuth");
        var user = new ClaimsPrincipal(identity);

        _authenticationState = Task.FromResult(new AuthenticationState(user));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_2e01b680450645b7a5f345f6d45a4960.Client;

namespace sv_2e01b680450645b7a5f345f6d45a4960.Auth;

/// <summary>
/// Persists the current user's claims into <see cref="PersistentComponentState"/>
/// so the WebAssembly runtime can reconstruct identity after the handoff.
/// </summary>
public sealed class PersistingServerAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingServerAuthenticationStateProvider(PersistentComponentState state)
    {
        _state = state;
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    /// <summary>
    /// Called by the server auth infrastructure to push the current <see cref="AuthenticationState"/>.
    /// </summary>
    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
        NotifyAuthenticationStateChanged(authenticationStateTask);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() =>
        _authenticationStateTask ?? throw new InvalidOperationException("Authentication state has not been set.");

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated != true)
            return;

        var email = principal.FindFirst(ClaimTypes.Email)?.Value
                    ?? principal.FindFirst(ClaimTypes.Name)?.Value;

        if (email is null)
            return;

        var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

        _state.PersistAsJson(nameof(UserInfo), new UserInfo
        {
            Email = email,
            Roles = roles,
        });
    }

    public void Dispose() => _subscription.Dispose();
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

@if (_userName is not null)
{
    <p><strong>Name:</strong> @_userName</p>

    <h2>Roles</h2>
    <ul>
        @foreach (var role in _roles)
        {
            <li>@role</li>
        }
    </ul>
}
else
{
    <p>Loading…</p>
}

@code {
    private string? _userName;
    private string[] _roles = [];

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var user = authState.User;

        if (user.Identity?.IsAuthenticated == true)
        {
            _userName = user.Identity.Name;
            _roles = user.FindAll(System.Security.Claims.ClaimTypes.Role)
                         .Select(c => c.Value)
                         .ToArray();
        }
    }
}

