using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;
using sv_2e01b680450645b7a5f345f6d45a4960.Auth;
using sv_2e01b680450645b7a5f345f6d45a4960.Client.Pages;
using sv_2e01b680450645b7a5f345f6d45a4960.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddAuthorization();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<AuthenticationStateProvider, PersistingServerAuthenticationStateProvider>();

var app = builder.Build();

// Fake authentication middleware: sets HttpContext.User to a hardcoded identity.
// The Blazor infrastructure passes this to PersistingServerAuthenticationStateProvider
// via IHostEnvironmentAuthenticationStateProvider.SetAuthenticationState().
app.Use(async (context, next) =>
{
    var claims = new[]
    {
        new Claim(ClaimTypes.Name, "bob@example.com"),
        new Claim(ClaimTypes.Email, "bob@example.com"),
        new Claim(ClaimTypes.Role, "User"),
        new Claim(ClaimTypes.Role, "Editor"),
    };
    context.User = new ClaimsPrincipal(new ClaimsIdentity(claims, "FakeAuth"));
    await next();
});

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

